code.C:
#include <stdio.h>
int main() {
    int T = 1; // single test case as there is no input
    for (int t = 0; t < T; ++t) {
        for (int i = 1; i <= 5; ++i) {
            printf("%d - %d\n", i, i * i);
        }
    }
    return 0;
}

